// // This module generates three status flags based on a 16-bit input.
// The 'flag_negative' output is set if the least significant bit (bit 0) of the input is high, indicating a negative value.
// The 'flag_zero' output is asserted when any bit of the input is high, indicating a zero value.
// The 'flag_positive' output is derived as the logical negation of both the 'flag_negative' and 'flag_zero' signals, indicating a positive value when neither of the other two flags is active.
module top_module(
    input [15:0] in,
    output flag_negative, flag_zero, flag_positive
    );assign flag_negative = in[15];
    assign flag_zero = ~(|in);
    assign flag_positive = ~(flag_negative | flag_zero);
endmodule

